class Solution {
public:
    int longestSubsequence(string s, int k) {
        int n = s.size();
        int res = 0;
        for (int mask = 0; mask < (1 << n); mask++) {
            string sub;
            for (int i = 0; i < n; i++) {
                if ((mask & (1 << i)) != 0) {
                    sub += s[i];
                }
            }
            int num = stoi(sub, 0, 2);
            if (num <= k) {
                res = max(res, (int)sub.size());
            }
        }
        return res;
    }
};

